import React, { useState, useEffect } from "react";
import Slider from "react-slick";
import { Card, Image, Rating, Placeholder } from "semantic-ui-react";
import "./Cards.css";
import { Link } from "react-router-dom";
const NextArrow = props => {
  const { className, onClick } = props;
  return (
    <button className={className} onClick={onClick}>
      <svg focusable="false" viewBox="0 0 24 24">
        <path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z" />
      </svg>
    </button>
  );
};
const PrevArrow = props => {
  const { className, onClick } = props;
  return (
    <button className={className} onClick={onClick}>
      <svg focusable="false" viewBox="0 0 24 24">
        <path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z" />
      </svg>
    </button>
  );
};

const settings = {
  infinite: false,
  slidesToShow: 6,
  slidesToScroll: 6,
  nextArrow: <NextArrow />,
  prevArrow: <PrevArrow />,
  responsive: [
    {
      breakpoint: 1440,
      settings: {
        slidesToShow: 5,
        slidesToScroll: 5
      }
    },
    {
      breakpoint: 1200,
      settings: {
        slidesToShow: 4,
        slidesToScroll: 4
      }
    },
    {
      breakpoint: 992,
      settings: {
        slidesToShow: 3,
        slidesToScroll: 3
      }
    },
    {
      breakpoint: 768,
      settings: {
        slidesToShow: 2,
        slidesToScroll: 2
      }
    }
  ]
};
// "https://react.semantic-ui.com/images/avatar/large/matthew.png"
function CourseItems(props) {
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    setTimeout(() => setIsLoading(false), 1000);
  }, []);
  const { courses } = props;

  return (
    <Slider {...settings}>
      {courses &&
        courses.map(
          (
            { title, id, headline, last_updated, level, objectives, image },
            i
          ) => (
            <div key={id}>
              <Link to={`/${id}`}>
                <Card fluid>
                  {isLoading ? (
                    <Placeholder>
                      <Placeholder.Image square />
                    </Placeholder>
                  ) : (
                    <Image src={image} />
                  )}

                  <Card.Content>
                    {isLoading ? (
                      <Placeholder>
                        <Placeholder.Header>
                          <Placeholder.Line length="very short" />
                          <Placeholder.Line length="medium" />
                        </Placeholder.Header>
                        <Placeholder.Paragraph>
                          <Placeholder.Line length="short" />
                          <Placeholder.Line length="short" />
                        </Placeholder.Paragraph>
                      </Placeholder>
                    ) : (
                      <React.Fragment>
                        <Card.Header>{title}</Card.Header>
                        <Card.Meta>{headline}</Card.Meta>
                        <Card.Description>
                          {`Level: ${level}`}
                        </Card.Description>
                      </React.Fragment>
                    )}
                  </Card.Content>
                  <Card.Content extra>
                    <Rating
                      icon="heart"
                      defaultRating={3.9}
                      maxRating={5}
                      size="mini"
                      disabled
                    />
                  </Card.Content>
                </Card>
              </Link>
            </div>
          )
        )}
    </Slider>
  );
}
const Cards = props => {
  const { category, courses } = props;
  return (
    <div>
      <h4>{category}</h4>
      <CourseItems courses={courses} fuck={props.children} />
    </div>
  );
};

export default Cards;
