import React from "react";
import Cards from "../components/Cards";
import { Segment, Container } from "semantic-ui-react";
import { connect } from "react-redux";
import { compose } from "redux";
import { getCourses } from "../store/courseActions";
import { firestoreConnect } from "react-redux-firebase";

function Home(props) {
	const { courses } = props;

	 props.getCourses(courses);


	return (
		<React.Fragment>
			<Segment padded className="masthead bg6">
				<Container>
					<div className="introduction">
						<a
							className="ui black version label"
							href="https://github.com/Semantic-Org/Semantic-UI/blob/master/RELEASE-NOTES.md"
						>
							2.3.3
						</a>
						<h1 className="ui inverted header">
							<span className="library">Udemy Clone</span>
							<span className="tagline">
								Online courses for your endless learning journey
							</span>
						</h1>
						<div className="ui hidden divider" />

						<a
							href="/introduction/getting-started.html"
							className="ui huge inverted download button"
						>
							Get Started
						</a>
						<a
							href="/introduction/new.html"
							className="ui huge inverted basic button"
						>
							New in 2.3
						</a>
					</div>
				</Container>
			</Segment>
			<Container>
				<Cards courses={courses} category="New" />
			</Container>
		</React.Fragment>
	);
}

const mapStateToProps = state => {
	return {
		courses: state.firestore.ordered.courses
	};
};

const mapDispatchToProps = dispatch => {
	return {
		getCourses: courses => dispatch(getCourses(courses))
	};
};
export default compose(
	connect(
		mapStateToProps,
		mapDispatchToProps
	),

	firestoreConnect([{ collection: "courses" }])
)(Home);

